﻿@page "/"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>ShipmentTracker - Home</PageTitle>

<h1>Shipment Tracker</h1>
<p class="lead">Welcome to the logistics management portal.</p>

<div class="row mt-4">
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Track a Shipment</h5>
                <p class="card-text">Enter your tracking number to check shipment status and estimated delivery.</p>
                <div class="input-group">
                    <input type="text" class="form-control" placeholder="Enter tracking number"
                           @bind="trackingNumber" @bind:event="oninput"
                           @onkeydown="HandleTrackKeyDown" />
                    <button class="btn btn-primary" @onclick="TrackShipment" disabled="@string.IsNullOrWhiteSpace(trackingNumber)">
                        Track
                    </button>
                </div>
            </div>
        </div>
    </div>
    <div class="col-md-6">
        <div class="card">
            <div class="card-body">
                <h5 class="card-title">Dispatcher Dashboard</h5>
                <p class="card-text">View and manage all shipments, update statuses, and monitor deliveries.</p>
                <a href="/shipments" class="btn btn-outline-primary">Go to Dashboard</a>
            </div>
        </div>
    </div>
</div>

@code {
    private string trackingNumber = string.Empty;

    private void TrackShipment()
    {
        if (!string.IsNullOrWhiteSpace(trackingNumber))
        {
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
        }
    }

    private void HandleTrackKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            TrackShipment();
        }
    }
}

