@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@FormatStatus(status)</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-secondary" @onclick="LoadShipments">Refresh</button>
    </div>
</div>

@if (shipments == null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments match the current filters.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td><span class="badge @GetStatusBadgeClass(shipment.Status)">@FormatStatus(shipment.Status)</span></td>
                        <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    value="@shipment.Status"
                                    @onchange="(e) => UpdateStatus(shipment, e)">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status" selected="@(shipment.Status == status)">@FormatStatus(status)</option>
                                }
                            </select>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string statusFilter = string.Empty;

    private IEnumerable<Shipment> FilteredShipments => shipments?.Where(s =>
        (string.IsNullOrWhiteSpace(filterText) ||
         s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
         s.Origin.Contains(filterText, StringComparison.OrdinalIgnoreCase) ||
         s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase)) &&
        (string.IsNullOrWhiteSpace(statusFilter) ||
         s.Status.ToString() == statusFilter)
    ) ?? [];

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
            shipment.Status = newStatus;
        }
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

@page "/track/{TrackingNumber}"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject NavigationManager Navigation
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>Track Shipment</PageTitle>

<h1>Track Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number"
                   @bind="searchTracking" @bind:event="oninput"
                   @onkeydown="HandleSearchKeyDown" />
            <button class="btn btn-primary" @onclick="SearchShipment" disabled="@string.IsNullOrWhiteSpace(searchTracking)">
                Track
            </button>
        </div>
    </div>
</div>

@if (loading)
{
    <p><em>Looking up shipment...</em></p>
}
else if (notFound)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment found with tracking number <code>@TrackingNumber</code>.
    </div>
}
else if (shipment != null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Tracking: <code>@shipment.TrackingNumber</code></h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span></dd>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>
                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@shipment.ShippedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>
                            <strong class="@(shipment.Status == ShipmentStatus.Delivered ? "text-success" : "text-primary")">
                                @shipment.EstimatedDelivery.ToString("MMMM dd, yyyy")
                            </strong>
                            @if (shipment.Status != ShipmentStatus.Delivered)
                            {
                                var daysRemaining = (shipment.EstimatedDelivery - DateTime.UtcNow).Days;
                                <br />
                                <small class="text-muted">
                                    @if (daysRemaining > 0)
                                    {
                                        @($"({daysRemaining} day{(daysRemaining == 1 ? "" : "s")} remaining)")
                                    }
                                    else if (daysRemaining == 0)
                                    {
                                        @("(Expected today)")
                                    }
                                    else
                                    {
                                        @($"(Overdue by {Math.Abs(daysRemaining)} day{(Math.Abs(daysRemaining) == 1 ? "" : "s")})")
                                    }
                                </small>
                            }
                        </dd>
                    </dl>
                </div>
            </div>

            <h6 class="mt-3">Delivery Progress</h6>
            <div class="progress" style="height: 25px;">
                <div class="progress-bar @GetProgressBarClass(shipment.Status)"
                     role="progressbar" style="width: @GetProgressPercent(shipment.Status)%"
                     aria-valuenow="@GetProgressPercent(shipment.Status)" aria-valuemin="0" aria-valuemax="100">
                    @FormatStatus(shipment.Status)
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? shipment;
    private bool loading = true;
    private bool notFound;
    private string searchTracking = string.Empty;

    protected override async Task OnParametersSetAsync()
    {
        searchTracking = TrackingNumber;
        await LoadShipment();
    }

    private async Task LoadShipment()
    {
        loading = true;
        notFound = false;
        shipment = null;

        try
        {
            shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(TrackingNumber);
            notFound = shipment == null;
        }
        catch
        {
            notFound = true;
        }
        finally
        {
            loading = false;
        }
    }

    private void SearchShipment()
    {
        if (!string.IsNullOrWhiteSpace(searchTracking))
        {
            Navigation.NavigateTo($"/track/{Uri.EscapeDataString(searchTracking.Trim())}");
        }
    }

    private void HandleSearchKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
        {
            SearchShipment();
        }
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning",
        _ => "bg-secondary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };
}

@page "/my-shipments"
@using Microsoft.AspNetCore.Components.Authorization
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService
@inject AuthenticationStateProvider AuthStateProvider
@attribute [Microsoft.AspNetCore.Authorization.Authorize]

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>
<p>View all shipments associated with your account.</p>

<div class="mb-3">
    <button class="btn btn-outline-secondary" @onclick="LoadShipments">Refresh</button>
</div>

@if (shipments == null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!shipments.Any())
{
    <div class="alert alert-info">
        You have no shipments on record.
    </div>
}
else
{
    <div class="row">
        @foreach (var shipment in shipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h6 class="card-title">
                            <code>@shipment.TrackingNumber</code>
                            <span class="badge @GetStatusBadgeClass(shipment.Status) float-end">@FormatStatus(shipment.Status)</span>
                        </h6>
                        <p class="card-text mb-1"><small class="text-muted">@shipment.Description</small></p>
                        <p class="card-text mb-1">
                            <strong>To:</strong> @shipment.Destination
