                            <span class="badge @GetStatusBadgeClass(shipment.Status) float-end">@FormatStatus(shipment.Status)</span>
                        </h6>
                        <p class="card-text mb-1"><small class="text-muted">@shipment.Description</small></p>
                        <p class="card-text mb-1">
                            <strong>To:</strong> @shipment.Destination
                        </p>
                        <p class="card-text">
                            <strong>Est. Delivery:</strong> @shipment.EstimatedDelivery.ToString("MMM dd, yyyy")
                        </p>
                    </div>
                    <div class="card-footer">
                        <a href="/track/@shipment.TrackingNumber" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private List<Shipment>? shipments;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        var authState = await AuthStateProvider.GetAuthenticationStateAsync();
        var email = authState.User.Identity?.Name ?? string.Empty;
        if (!string.IsNullOrEmpty(email))
        {
            shipments = await ShipmentService.GetShipmentsByCustomerAsync(email);
        }
        else
        {
            shipments = [];
        }
    }

    private static string FormatStatus(ShipmentStatus status) => status switch
    {
        ShipmentStatus.InTransit => "In Transit",
        ShipmentStatus.OutForDelivery => "Out for Delivery",
        _ => status.ToString()
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

